      <Box style={{ flex: 1, minWidth: 0 }}>
        <Group gap={8} mb={6} align="center">
          <Text size="xs" fw={600} c="orange">Claude</Text>
          {reason && <Badge color="orange" size="xs" variant="light">{reason}</Badge>}
          {stop && <TimeAgo iso={stop.timestamp} />}
        </Group>
        {stop && msg && (
          <Box style={{
