              {sum.workflowLearnings.map((it, i) => <Text key={i} size="xs">· {it}</Text>)}
            </Box>
          ) : null}
          {sum?.friction?.length ? (
            <Box>
              <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={2}>△ Friction</Text>
